            hasBackgroundIcon: true,
          },
        ]}
        type="list"
      />
    </Section>
  );
}

function SeparatorValidation() {
  return (
    <Section title="8. SeparatorHorizontal">
      <StatusBadge status="ok" />
      <Text type="bodySM" mb="nano">
        Content before separator
      </Text>
      <SeparatorHorizontal
        mb="nano"
        mt="nano"
        bgColor="BRAND_COMPLEMENT_02"
        height={1}
        width="100%"
      />
      <Text type="bodySM">Content after separator</Text>
    </Section>
  );
}

function BackDropBottomValidation() {
  return (
    <Section title="9. BackDropBottom">
      <StatusBadge status="warn" />
      <Text type="bodySM" color="INTENSE_COLOR_03" mb="nano">
        BackDropBottom depends on react-native-modalize which requires native
        modules (GestureHandler, Animated). It will NOT render in the Storybook
        web context. Use a plain View/ScrollView wrapper as substitute for
        SDUI stories.
      </Text>
    </Section>
  );
}

function LoadingValidation() {
  return (
    <Section title="10. Loading">
      <StatusBadge status="warn" />
      <Text type="bodySM" color="INTENSE_COLOR_03" mb="nano">
        Loading depends on lottie-react-native which requires native Lottie
        bindings. It will NOT render in the Storybook web context. Use a
        simple ActivityIndicator or Text fallback for SDUI stories.
      </Text>
    </Section>
  );
}

function DSComponentValidation() {
  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 480 }}>
        <Text type="headingMDL" mb="smaller">
          DS Component Validation — SP_0001.1
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Validates all @semparar/design-system-app components used in voucher
          screens. Each section shows the component with realistic props matching
          InvoiceCashback screen usage.
        </Text>
        <SeparatorHorizontal
          mb="smaller"
          bgColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
        />
        <TextValidation />
        <ButtonValidation />
        <BoxValidation />
        <InputBoxValidation />
        <AlertValidation />
        <IconValidation />
        <ListTextIconValidation />
        <SeparatorValidation />
        <BackDropBottomValidation />
        <LoadingValidation />

        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm" mt="smaller">
          <Text type="subtitleXXL" mb="nano">
            Summary
          </Text>
          <Text type="bodyMD" mb="nano">
            8/10 components render correctly in Storybook web context.
          </Text>
          <Text type="bodySM" color="INTENSE_COLOR_03">
            BackDropBottom (Modalize) and Loading (Lottie) require native modules
            and cannot render on web. SDUI adapters should provide web-safe
            fallbacks for these two components.
          </Text>
        </Box>
      </View>
    </ScrollView>
  );
}

const meta: Meta<typeof DSComponentValidation> = {
  title: 'Validation/DS Components',
  component: DSComponentValidation,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const AllComponents: Story = {};

